import { createFileRoute } from '@tanstack/react-router';
import { useState, useEffect } from 'react';
import {
  listWorkflows,
  createWorkflow,
  updateWorkflow,
  deleteWorkflow,
  type Workflow,
} from '../api';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Label } from '@/components/ui/label';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';

export const workflowsRoute = createFileRoute({
  getParentRoute: () => null,
  path: '/workflows',
  component: () => {
    const [workflows, setWorkflows] = useState<Workflow[]>([]);
    const [selectedWorkflow, setSelectedWorkflow] = useState<Workflow | null>(null);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [name, setName] = useState('');
    const [description, setDescription] = useState('');

    useEffect(() => {
      listWorkflows().then(setWorkflows);
    }, []);

    const openDialogForNew = () => {
      setSelectedWorkflow(null);
      setName('');
      setDescription('');
      setIsDialogOpen(true);
    };

    const openDialogForEdit = (workflow: Workflow) => {
      setSelectedWorkflow(workflow);
      setName(workflow.name);
      setDescription(workflow.description);
      setIsDialogOpen(true);
    };

    const saveWorkflow = async () => {
      if (name.trim() === '') {
        alert('Name is required');
        return;
      }
      if (selectedWorkflow) {
        const updated = await updateWorkflow(selectedWorkflow.id, { name, description });
        setWorkflows((ws) =>
          ws.map((w) => (w.id === updated.id ? updated : w))
        );
      } else {
        const created = await createWorkflow({ name, description });
        setWorkflows((ws) => [...ws, created]);
      }
      setIsDialogOpen(false);
    };

    const removeWorkflow = async (id: string) => {
      await deleteWorkflow(id);
      setWorkflows((ws) => ws.filter((w) => w.id !== id));
    };
